#!/usr/bin/env python3
"""Generate src/ldpc_tables.c from Python sparse parity-generator matrices.

Reads py80211/ldpc_tables.py P_GEN (scipy sparse) and outputs C arrays
in CSR format (row_ptr + col_idx, no data since all entries are 1).

Run from the repo root:
    python scripts/gen_ldpc_tables_c.py

Output: src/ldpc_tables.c (~750 KB)
"""

import sys
from pathlib import Path

import numpy as np

REPO_ROOT = Path(__file__).resolve().parent.parent
sys.path.insert(0, str(REPO_ROOT / "python"))

from py80211.ldpc_tables import P_GEN  # noqa: E402

OUT_FILE = REPO_ROOT / "src" / "ldpc_tables.c"

RATES = [("1/2", 1, 2), ("2/3", 2, 3), ("3/4", 3, 4), ("5/6", 5, 6)]
CW_LENS = [648, 1296, 1944]


def fmt_array(name: str, data: np.ndarray, ctype: str, per_line: int = 16) -> str:
    """Format an integer array as a C static const definition."""
    lines = [f"static const {ctype} {name}[] = {{"]
    vals = data.tolist()
    for i in range(0, len(vals), per_line):
        chunk = vals[i : i + per_line]
        lines.append("    " + ", ".join(str(v) for v in chunk) + ",")
    lines.append("};")
    return "\n".join(lines)


def rate_label(rate_n: int, rate_d: int) -> str:
    return f"r{rate_n}{rate_d}"


def main() -> None:
    lines = []
    lines.append("/**")
    lines.append(" * ldpc_tables.c — LDPC parity-generator matrices in CSR format.")
    lines.append(" *")
    lines.append(" * Auto-generated by scripts/gen_ldpc_tables_c.py — DO NOT EDIT.")
    lines.append(" *")
    lines.append(" * 12 codes: codeword lengths {648, 1296, 1944} x rates {1/2, 2/3, 3/4, 5/6}")
    lines.append(" * Each P_GEN matrix is (N-K) x K, stored as CSR (row_ptr + col_idx).")
    lines.append(" * All entries are binary 1, so no data array is needed.")
    lines.append(" */")
    lines.append("")
    lines.append('#include "lib80211/ldpc.h"')
    lines.append('#include <stddef.h>')
    lines.append("")

    # Generate arrays for each (cw_len, rate) combo
    struct_entries = []

    for rate_str, rate_n, rate_d in RATES:
        for cw_len in CW_LENS:
            pgen = P_GEN[rate_str][cw_len].tocsr()
            n_rows, n_cols = pgen.shape
            nnz = pgen.nnz

            label = f"pgen_{cw_len}_{rate_label(rate_n, rate_d)}"

            # Validate that all data entries are 1
            assert np.all(pgen.data == 1.0), f"Non-binary data in P_GEN[{rate_str}][{cw_len}]"

            # row_ptr: indptr array (n_rows + 1 entries), needs uint32 (nnz can exceed 65535)
            row_ptr = pgen.indptr.astype(np.uint32)

            # col_idx: indices array (nnz entries), fits in uint16 (max col = 1620)
            col_idx = pgen.indices.astype(np.uint32)
            assert col_idx.max() <= 65535, f"col_idx overflow: max={col_idx.max()}"
            col_idx_u16 = col_idx.astype(np.uint16)

            lines.append(f"/* P_GEN rate={rate_str}, cw_len={cw_len}: "
                         f"{n_rows}x{n_cols}, nnz={nnz} */")
            lines.append(fmt_array(f"{label}_row_ptr", row_ptr, "uint32_t"))
            lines.append("")
            lines.append(fmt_array(f"{label}_col_idx", col_idx_u16, "uint16_t"))
            lines.append("")

            struct_entries.append((cw_len, rate_n, rate_d, label, n_rows, n_cols, nnz))

    # Generate the lookup table
    lines.append("/* ===== Lookup table ===== */")
    lines.append("")
    lines.append("typedef struct {")
    lines.append("    int cw_len;")
    lines.append("    int rate_n;")
    lines.append("    int rate_d;")
    lines.append("    lib80211_ldpc_pgen pgen;")
    lines.append("} ldpc_table_entry;")
    lines.append("")
    lines.append(f"static const ldpc_table_entry LDPC_TABLE[{len(struct_entries)}] = {{")
    for cw_len, rate_n, rate_d, label, n_rows, n_cols, nnz in struct_entries:
        lines.append(f"    {{ {cw_len}, {rate_n}, {rate_d}, "
                     f"{{ {n_rows}, {n_cols}, {nnz}, "
                     f"{label}_row_ptr, {label}_col_idx }} }},")
    lines.append("};")
    lines.append("")

    # Generate the lookup function
    lines.append("const lib80211_ldpc_pgen *lib80211_ldpc_get_pgen(int cw_len, int rate_n, int rate_d) {")
    lines.append(f"    for (int i = 0; i < {len(struct_entries)}; i++) {{")
    lines.append("        if (LDPC_TABLE[i].cw_len == cw_len &&")
    lines.append("            LDPC_TABLE[i].rate_n == rate_n &&")
    lines.append("            LDPC_TABLE[i].rate_d == rate_d) {")
    lines.append("            return &LDPC_TABLE[i].pgen;")
    lines.append("        }")
    lines.append("    }")
    lines.append("    return NULL;")
    lines.append("}")
    lines.append("")

    # Write output
    content = "\n".join(lines)
    OUT_FILE.write_text(content, encoding="utf-8")
    size_kb = OUT_FILE.stat().st_size / 1024
    print(f"Generated {OUT_FILE} ({size_kb:.0f} KB)")
    print(f"  {len(struct_entries)} codes, total nnz = "
          f"{sum(e[6] for e in struct_entries)}")

    # --- Generate test-only H_SUB header for syndrome checking ---
    generate_hsub_header()


def generate_hsub_header() -> None:
    """Generate test/ldpc_hsub.h with circulant sub-matrix tables."""
    from py80211.ldpc_tables import H_SUB, Z  # noqa: E402

    HSUB_FILE = REPO_ROOT / "test" / "ldpc_hsub.h"

    lines = []
    lines.append("/**")
    lines.append(" * ldpc_hsub.h — H_SUB circulant sub-matrices for LDPC syndrome testing.")
    lines.append(" *")
    lines.append(" * Auto-generated by scripts/gen_ldpc_tables_c.py — DO NOT EDIT.")
    lines.append(" * Test-only: used to expand full H matrix and verify H*c = 0.")
    lines.append(" */")
    lines.append("")
    lines.append("#ifndef LDPC_HSUB_H")
    lines.append("#define LDPC_HSUB_H")
    lines.append("")
    lines.append("#include <stdint.h>")
    lines.append("")
    lines.append("/* Expansion factors */")
    lines.append("static const int LDPC_Z[] = { 27, 54, 81 };  /* indexed by cw: 648->0, 1296->1, 1944->2 */")
    lines.append("")

    # All H_SUB matrices are M x 24, where M depends on rate
    rate_m = {"1/2": 12, "2/3": 8, "3/4": 6, "5/6": 4}

    for rate_str, rate_n, rate_d in RATES:
        m = rate_m[rate_str]
        for cw_len in CW_LENS:
            hsub = H_SUB[rate_str][cw_len]
            label = f"HSUB_{cw_len}_r{rate_n}{rate_d}"
            lines.append(f"/* H_SUB rate={rate_str}, cw_len={cw_len}: {m}x24 */")
            lines.append(f"static const uint8_t {label}[{m}][24] = {{")
            for row in hsub:
                lines.append("    {" + ", ".join(str(int(v)) for v in row) + "},")
            lines.append("};")
            lines.append("")

    # Lookup structure
    lines.append("typedef struct {")
    lines.append("    int cw_len;")
    lines.append("    int rate_n;")
    lines.append("    int rate_d;")
    lines.append("    int m;        /* number of check rows (in sub-matrix blocks) */")
    lines.append("    int z;        /* expansion factor */")
    lines.append("    const uint8_t (*hsub)[24];")
    lines.append("} ldpc_hsub_entry;")
    lines.append("")
    lines.append("static const ldpc_hsub_entry LDPC_HSUB_TABLE[] = {")
    for rate_str, rate_n, rate_d in RATES:
        m = rate_m[rate_str]
        for cw_len in CW_LENS:
            z = Z[cw_len]
            label = f"HSUB_{cw_len}_r{rate_n}{rate_d}"
            lines.append(f"    {{ {cw_len}, {rate_n}, {rate_d}, {m}, {z}, {label} }},")
    lines.append("};")
    lines.append("")
    lines.append("#define LDPC_HSUB_TABLE_LEN 12")
    lines.append("")
    lines.append("#endif /* LDPC_HSUB_H */")
    lines.append("")

    content = "\n".join(lines)
    HSUB_FILE.write_text(content, encoding="utf-8")
    size_kb = HSUB_FILE.stat().st_size / 1024
    print(f"Generated {HSUB_FILE} ({size_kb:.0f} KB)")


if __name__ == "__main__":
    main()
